package com.example.biometricauth

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.widget.Button
import android.widget.EditText
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat

object Prefs {
    private const val PREF_NAME = "auth_prefs"
    private const val KEY_AUTHENTICATED = "authenticated"

    fun isAuthenticated(context: Context): Boolean {
        return context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE)
            .getBoolean(KEY_AUTHENTICATED, false)
    }

    fun setAuthenticated(context: Context, value: Boolean) {
        context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE)
            .edit()
            .putBoolean(KEY_AUTHENTICATED, value)
            .apply()
    }

    fun clear(context: Context) {
        setAuthenticated(context, false)
    }
}

class LoginActivity : AppCompatActivity() {

    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (Prefs.isAuthenticated(this)) {
            navigateToHome()
            return
        }

        setContentView(R.layout.activity_login)

        val passwordInput = findViewById<EditText>(R.id.etPassword)
        val loginButton = findViewById<Button>(R.id.btnLogin)
        val biometricButton = findViewById<Button>(R.id.btnBiometric)

        setupBiometricPrompt()
        setupPromptInfo()

        when (BiometricManager.from(this).canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK)) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                biometricButton.isEnabled = true
                biometricButton.setOnClickListener {
                    biometricPrompt.authenticate(promptInfo)
                }
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                biometricButton.isEnabled = false
                Toast.makeText(this, "No fingerprint enrolled. Use password.", Toast.LENGTH_LONG).show()
            }
            else -> {
                biometricButton.isEnabled = false
                Toast.makeText(this, "Biometric unavailable. Use password.", Toast.LENGTH_LONG).show()
            }
        }

        loginButton.setOnClickListener {
            val password = passwordInput.text.toString()
            if (password == "1234") {
                Prefs.setAuthenticated(this, true)
                Toast.makeText(this, "Login successful", Toast.LENGTH_SHORT).show()
                navigateToHome()
            } else {
                Toast.makeText(this, "Invalid password", Toast.LENGTH_SHORT).show()
            }
        }
    }

    private fun setupBiometricPrompt() {
        val executor = ContextCompat.getMainExecutor(this)
        biometricPrompt = BiometricPrompt(
            this,
            executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    Prefs.setAuthenticated(this@LoginActivity, true)
                    Toast.makeText(this@LoginActivity, "Fingerprint verified", Toast.LENGTH_SHORT).show()
                    navigateToHome()
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    Toast.makeText(
                        this@LoginActivity,
                        "Biometric unavailable. Please use password.",
                        Toast.LENGTH_SHORT
                    ).show()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Toast.makeText(
                        this@LoginActivity,
                        "Fingerprint not recognized. Use password if needed.",
                        Toast.LENGTH_SHORT
                    ).show()
                }
            }
        )
    }

    private fun setupPromptInfo() {
        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Fingerprint Sign In")
            .setSubtitle("Authenticate quickly with your fingerprint")
            .setDescription("Use your fingerprint to continue")
            .setNegativeButtonText("Use Password")
            .build()
    }

    private fun navigateToHome() {
        startActivity(Intent(this, HomeActivity::class.java))
        finish()
    }
}

class HomeActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        setContentView(R.layout.activity_home)

        val logoutButton = findViewById<Button>(R.id.btnLogout)
        logoutButton.setOnClickListener {
            Prefs.clear(this)
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
        }
    }
}